SELECT id, owner_id, document_id, kind, filename, mime_type,
       bucket, storage_key, file_size, width, height, sha256, created_at, deleted_at
FROM editor_asset
WHERE deleted_at IS NULL

    AND document_id = #{documentId}


    AND kind = #{kind}

ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM editor_asset
WHERE deleted_at IS NULL

    AND document_id = #{documentId}


    AND kind = #{kind}
